  const trimmed = value.trim();
  if (trimmed.length === 0 || trimmed.length > MAX_CLIENT_ID_LENGTH) {
    return 'invalid';
  }

  if (!CLIENT_ID_PATTERN.test(trimmed)) {
    return 'invalid';
  }

