      : [];

  const allowed = new Set();
  for (const value of rawValues) {
    if (typeof value !== 'string') {
      continue;
    }

    const trimmed = value.trim();
    if (
      trimmed.length > 0 &&
      trimmed.length <= MAX_CLIENT_ID_LENGTH &&
      CLIENT_ID_PATTERN.test(trimmed)
