  return createNodeServer(async (request, response) => {
    const url = new URL(request.url || '/', 'http://localhost');
    const requestId = getRequestId(request);
    const requestStartedAt = process.hrtime.bigint();
    let statusCode = 500;
    let writeAuth = null;

    const reply = (code, payload, extraHeaders) => {
      statusCode = code;
      return sendJson(response, code, payload, requestId, extraHeaders);
    };

    try {
      if (request.method === 'GET' && url.pathname === '/health') {
        return reply(200, {
          status: 'ok',
          service: 'daio-api',
          timestamp: now().toISOString()
        });
      }

      if (request.method === 'GET' && url.pathname === '/v1/increments') {
        try {
          const increments = await store.list();
          return reply(200, { increments });
        } catch (error) {
          return reply(500, { error: error.message });
        }
      }

      if (request.method === 'POST' && url.pathname === '/v1/increments') {
        const clientId = getClientId(request);
        const acceptedWriteTokens = getAcceptedWriteTokens(writeToken, writeTokenNext);
        const isClientAllowlistEnforced = allowedClientIds.size > 0;
        const isClientAllowed =
          !isClientAllowlistEnforced ||
          (clientId !== 'missing' && clientId !== 'invalid' && allowedClientIds.has(clientId));
        const clientAllowlist = isClientAllowlistEnforced
          ? (isClientAllowed ? 'allowed' : 'rejected')
          : 'not_enforced';

        if (acceptedWriteTokens.size > 0) {
          const bearerToken = readBearerToken(request);
          const tokenLabel =
            typeof bearerToken === 'string'
              ? (acceptedWriteTokens.get(bearerToken) ?? 'unknown')
              : 'missing';
          const isAuthorized = tokenLabel === 'current' || tokenLabel === 'next';
          writeAuth = {
            required: true,
            result: isAuthorized ? 'authorized' : 'rejected',
            tokenLabel,
            clientId,
            clientAllowlist
          };

          if (!isAuthorized) {
            return reply(
              401,
              { error: 'Missing or invalid bearer token.' },
              { 'www-authenticate': 'Bearer realm="daio-api"' }
            );
          }
        } else {
          writeAuth = {
            required: false,
            result: 'not_required',
            tokenLabel: 'not_required',
            clientId,
            clientAllowlist
          };
        }

        if (!isClientAllowed) {
          writeAuth.result = 'rejected';
          return reply(403, { error: 'Client is not allowed.' });
        }

        const body = await readJsonBody(request);
        if (body.error) {
          return reply(body.status, { error: body.error });
        }

